import Nav from '@/components/Nav'; import { requireUser } from '@/lib/auth'; import { prisma } from '@/lib/db'; import Link from 'next/link';
export default async function Lecturer(){ const user=await requireUser(['LECTURER','ADMIN']); const courses=await prisma.course.findMany({where:user.role==='ADMIN'?{}:{lecturerId:user.id},include:{enrollments:true,sections:{include:{lessons:true}},chunks:true}}); return <><Nav/><main className="mx-auto max-w-7xl px-5 py-10"><div className="flex items-center justify-between"><div><h1 className="text-4xl font-black">Lecturer dashboard</h1><p className="text-slate-600">Create courses, upload resources, monitor students and chatbot indexing.</p></div><Link className="btn" href="/lecturer/courses/new">Create course</Link></div><div className="mt-8 grid gap-6 md:grid-cols-2">{courses.map(c=><div key={c.id} className="card p-6"><h2 className="text-2xl font-black">{c.title}</h2><p className="mt-2 text-sm text-slate-600">{c.enrollments.length} students • {c.sections.reduce((n,s)=>n+s.lessons.length,0)} lessons • {c.chunks.length} AI chunks</p><Link className="btn-secondary mt-5" href={`/lecturer/courses/${c.id}/edit`}>Manage</Link></div>)}</div></main></> }
